import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type CommitEntry = {
  sha: string
  author: string
  date: string
  message: string
}

type GitLogData = {
  branch: string
  commits: CommitEntry[]
}

type GitDelta = {
  newCommits: CommitEntry[]
}

const parseGitLog = (raw: string): CommitEntry[] =>
  raw
    .trim()
    .split('\n')
    .filter(Boolean)
    .map((line) => {
      const [sha = '', author = '', date = '', ...rest] = line.split('|')
      return { sha, author, date, message: rest.join('|') }
    })

export const gitCommitSensor: SensorFactory = {
  name: 'git-commits',
  snapshotPath: 'git-commits.json',

  async read(signal: AbortSignal): Promise<unknown> {
    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    // Fetch latest remote state for main
    const fetchProc = Bun.spawn(['git', 'fetch', 'origin', 'main'], {
      stdout: 'ignore',
      stderr: 'ignore',
    })
    await fetchProc.exited
    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    // Read the latest 50 commits on origin/main
    const logProc = Bun.spawn(
      ['git', 'log', 'origin/main', '--pretty=format:%H|%an|%aI|%s', '-n', '50'],
      { stdout: 'pipe', stderr: 'ignore' },
    )
    const raw = await new Response(logProc.stdout).text()
    await logProc.exited
    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    const commits = parseGitLog(raw)

    return { branch: 'main', commits } satisfies GitLogData
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as GitLogData

    // First run — report all commits as the initial delta
    if (!previous) {
      return curr.commits.length > 0 ? { newCommits: curr.commits } satisfies GitDelta : null
    }

    const prev = previous.data as GitLogData
    const knownShas = new Set(prev.commits.map((c) => c.sha))
    const newCommits = curr.commits.filter((c) => !knownShas.has(c.sha))

    return newCommits.length > 0 ? { newCommits } satisfies GitDelta : null
  },
}

