import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type HealthStatus = {
  status: number
  ok: boolean
  timestamp: string
}

export const healthSensor: SensorFactory = {
  name: 'http-health',
  snapshotPath: 'http-health.json',

  async read(signal: AbortSignal): Promise<unknown> {
    const url = process.env.HEALTH_ENDPOINT_URL ?? 'https://api.example.com/health'
    try {
      const response = await fetch(url, { signal })
      return {
        status: response.status,
        ok: response.ok,
        timestamp: new Date().toISOString(),
      } satisfies HealthStatus
    } catch (error) {
      if (signal.aborted) throw new DOMException('Aborted', 'AbortError')
      return {
        status: 0,
        ok: false,
        timestamp: new Date().toISOString(),
      } satisfies HealthStatus
    }
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as HealthStatus

    if (!previous) {
      return curr.ok ? null : curr
    }

    const prev = previous.data as HealthStatus

    if (curr.status === prev.status) return null

    return {
      previousStatus: prev.status,
      currentStatus: curr.status,
      ok: curr.ok,
      timestamp: curr.timestamp,
    }
  },
}

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type HealthDelta = {
  previousStatus: number
  currentStatus: number
  ok: boolean
  timestamp: string
}

const isNon200HealthDelta = ({ type, detail }: { type: string; detail: unknown }): boolean => {
  if (type !== AGENT_EVENTS.sensor_delta) return false
  const sensorDetail = detail as SensorDeltaDetail
  if (sensorDetail.sensor !== 'http-health') return false
  const delta = sensorDetail.delta as HealthDelta
  return !delta.ok
}

const discordNotificationHandler: DefaultHandlers = {
  [AGENT_EVENTS.message]: ({ detail }) => {
    const msg = detail as { source?: string; content?: string }
    if (msg.source !== 'proactive') return
    const webhookUrl = process.env.DISCORD_WEBHOOK_URL
    if (!webhookUrl) return
    fetch(webhookUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ content: msg.content }),
    }).catch(() => {/* non-fatal */})
  },
}

export const healthAlertGoal = createGoal((_trigger) => ({
  threads: {
    'health-alert': bThread(
      [
        bSync({
          waitFor: isNon200HealthDelta,
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt:
                'The HTTP health check detected a non-200 status code. ' +
                'Compose an alert message describing the status change and ' +
                'send it as a proactive notification to the Discord channel.',
            },
          },
        }),
      ],
      true,
    ),
  },
  handlers: discordNotificationHandler,
}))

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'

type AccumulatedDelta = {
  sensor: string
  delta: unknown
  timestamp: string
}

const formatDigestEmail = (deltas: AccumulatedDelta[]): string => {
  const grouped: Record<string, AccumulatedDelta[]> = {}
  for (const entry of deltas) {
    const list = grouped[entry.sensor] ?? []
    list.push(entry)
    grouped[entry.sensor] = list
  }

  const sections = Object.entries(grouped)
    .map(([sensor, entries]) => {
      const rows = entries
        .map(
          (e) =>
            `<tr><td>${e.timestamp}</td><td><pre>${JSON.stringify(e.delta, null, 2)}</pre></td></tr>`,
        )
        .join('\n')

      return `
        <h2>${sensor}</h2>
        <table border="1" cellpadding="6" cellspacing="0">
          <thead><tr><th>Time</th><th>Delta</th></tr></thead>
          <tbody>${rows}</tbody>
        </table>`
    })
    .join('\n')

  return `
    <html>
      <body>
        <h1>Daily Sensor Digest</h1>
        <p>${deltas.length} change(s) detected in the past 24 hours.</p>
        ${sections}
      </body>
    </html>`
}

export const emailDigestGoal = createGoal((_trigger) => {
  const collected: AccumulatedDelta[] = []

  const handlers: DefaultHandlers = {
    [AGENT_EVENTS.sensor_delta]: ({ detail }) => {
      const { sensor, delta } = detail as SensorDeltaDetail
      collected.push({
        sensor,
        delta,
        timestamp: new Date().toISOString(),
      })
    },

    [AGENT_EVENTS.message]: ({ detail }) => {
      const msg = detail as { source?: string; content?: string }
      if (msg.source !== 'proactive') return

      const smtpRelayUrl = process.env.SMTP_RELAY_URL
      if (!smtpRelayUrl) return

      const cutoff = Date.now() - 24 * 60 * 60 * 1000
      const recentDeltas = collected.filter(
        (d) => new Date(d.timestamp).getTime() >= cutoff,
      )

      if (recentDeltas.length === 0) return

      const html = formatDigestEmail(recentDeltas)

      fetch(smtpRelayUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          to: process.env.DIGEST_RECIPIENT,
          subject: `Daily Sensor Digest — ${new Date().toLocaleDateString()}`,
          html,
        }),
      }).catch(() => {
        /* smtp relay failure is non-fatal */
      })

      // Drain delivered deltas
      collected.length = 0
    },
  }

  return {
    threads: {
      'daily-email-digest': bThread(
        [
          // Step 1: Gate — wait for at least one sensor delta to arrive
          bSync({
            waitFor: ({ type, detail }) =>
              type === AGENT_EVENTS.sensor_delta &&
              Boolean((detail as SensorDeltaDetail).delta),
          }),

          // Step 2: Wait for the 8 AM tick (handler keeps accumulating in the background)
          bSync({
            waitFor: ({ type }) =>
              type === AGENT_EVENTS.tick && new Date().getHours() === 8,
          }),

          // Step 3: Request the agent to compose and send the digest
          bSync({
            request: {
              type: AGENT_EVENTS.task,
              detail: {
                prompt:
                  'Compose and send the daily digest email summarizing all sensor changes collected over the past 24 hours',
              },
            },
          }),
        ],
        true, // repeat: restart the cycle after each digest is sent
      ),
    },
    handlers,
  }
})

import type { SensorFactory, SensorSnapshot } from 'src/agent/agent.types.ts'

type Backend = 'local' | 'cloud'

type BackendStatus = {
  backend: Backend
  endpoint: string
  latencyMs: number
  checkedAt: string
}

type BackendDelta = {
  from: Backend | null
  to: Backend
  endpoint: string
}

const LOCAL_PROBE_TIMEOUT_MS = 3_000

export const inferenceBackendSensor: SensorFactory = {
  name: 'inference-backend',
  snapshotPath: 'inference-backend.json',

  async read(signal: AbortSignal): Promise<unknown> {
    const localEndpoint = process.env.LOCAL_INFERENCE_URL ?? 'http://localhost:11434/api/tags'
    const start = performance.now()

    try {
      const combined = AbortSignal.any([signal, AbortSignal.timeout(LOCAL_PROBE_TIMEOUT_MS)])
      const response = await fetch(localEndpoint, { signal: combined, method: 'GET' })

      if (response.ok) {
        return {
          backend: 'local',
          endpoint: localEndpoint,
          latencyMs: Math.round(performance.now() - start),
          checkedAt: new Date().toISOString(),
        } satisfies BackendStatus
      }
    } catch {
      // Local endpoint unavailable or timed out — fall through to cloud
    }

    if (signal.aborted) throw new DOMException('Aborted', 'AbortError')

    return {
      backend: 'cloud',
      endpoint: process.env.CLOUD_INFERENCE_URL ?? 'https://api.anthropic.com',
      latencyMs: Math.round(performance.now() - start),
      checkedAt: new Date().toISOString(),
    } satisfies BackendStatus
  },

  diff(current: unknown, previous: SensorSnapshot | null): unknown | null {
    const curr = current as BackendStatus

    // First run: report initial backend as a transition from null
    if (!previous) {
      return { from: null, to: curr.backend, endpoint: curr.endpoint } satisfies BackendDelta
    }

    const prev = previous.data as BackendStatus

    // No change — suppress delta
    if (prev.backend === curr.backend) return null

    return { from: prev.backend, to: curr.backend, endpoint: curr.endpoint } satisfies BackendDelta
  },
}

export type { BackendStatus, BackendDelta, Backend }

import { createGoal } from 'src/agent/agent.factories.ts'
import { bThread, bSync } from 'src/behavioral/behavioral.utils.ts'
import { AGENT_EVENTS } from 'src/agent/agent.constants.ts'
import type { SensorDeltaDetail } from 'src/agent/agent.types.ts'
import type { DefaultHandlers } from 'src/behavioral/behavioral.types.ts'
import type { BackendDelta } from './sensor.ts'

const AGGRESSIVE_INTERVAL_MS = 300_000     // 5 minutes  — local GPU
const CONSERVATIVE_INTERVAL_MS = 7_200_000 // 2 hours    — cloud API

const SET_HEARTBEAT = 'set_heartbeat' as const

const isBackendTransition = (detail: unknown, targetBackend: string): boolean => {
  const d = detail as SensorDeltaDetail
  return (
    d.sensor === 'inference-backend' &&
    (d.delta as BackendDelta).to === targetBackend
  )
}

export const costAwareHeartbeatGoal = createGoal((_trigger) => ({
  threads: {
    /**
     * Detects fallback to cloud API and switches to a conservative 2-hour
     * heartbeat to minimize inference cost.
     */
    'cloud-fallback-conserve': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) =>
            type === AGENT_EVENTS.sensor_delta &&
            isBackendTransition(detail, 'cloud'),
        }),
        bSync({
          request: {
            type: SET_HEARTBEAT,
            detail: { intervalMs: CONSERVATIVE_INTERVAL_MS },
          },
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt: [
                'Inference backend fell back to cloud API.',
                `Heartbeat widened to ${CONSERVATIVE_INTERVAL_MS / 60_000} minutes to reduce cost.`,
                'Log this transition for cost tracking.',
              ].join(' '),
            },
          },
        }),
      ],
      true, // repeat — keep watching for future transitions
    ),

    /**
     * Detects return to local GPU and restores the aggressive 5-minute
     * heartbeat for responsive monitoring.
     */
    'local-restore-aggressive': bThread(
      [
        bSync({
          waitFor: ({ type, detail }) =>
            type === AGENT_EVENTS.sensor_delta &&
            isBackendTransition(detail, 'local'),
        }),
        bSync({
          request: {
            type: SET_HEARTBEAT,
            detail: { intervalMs: AGGRESSIVE_INTERVAL_MS },
          },
        }),
        bSync({
          request: {
            type: AGENT_EVENTS.task,
            detail: {
              prompt: [
                'Inference backend restored to local GPU.',
                `Heartbeat tightened to ${AGGRESSIVE_INTERVAL_MS / 60_000} minutes for aggressive monitoring.`,
                'Log this transition for cost tracking.',
              ].join(' '),
            },
          },
        }),
      ],
      true,
    ),
  },

  handlers: {
    [SET_HEARTBEAT]: ({ detail }) => {
      const { intervalMs } = detail as { intervalMs: number }
      console.log(
        `[cost-aware-heartbeat] set_heartbeat → ${intervalMs}ms (${intervalMs / 60_000} min)`,
      )
      // The agent loop's built-in set_heartbeat responder mutates the polling
      // interval. This handler provides local observability logging.
    },
  } satisfies DefaultHandlers,
}))

import { createAgentLoop } from 'src/agent/agent.loop.ts'
import { inferenceBackendSensor } from './sensor.ts'
import { costAwareHeartbeatGoal } from './goal.ts'

// Start optimistic — assume local GPU is available. The sensor's first read
// will immediately detect if we're actually on cloud and the goal will widen
// the heartbeat to 2 hours on the very first cycle.
const INITIAL_INTERVAL_MS = 300_000 // 5 minutes

export const createCostAwareAgent = () =>
  createAgentLoop({
    proactive: {
      sensors: [inferenceBackendSensor],
      goals: [costAwareHeartbeatGoal],
      intervalMs: INITIAL_INTERVAL_MS,
    },
  })
